import{_ as c,c as t,a1 as a,o as i}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Quét Mạng Mục Tiêu","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/0-Scanning-a-Target-Network.md","filePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/0-Scanning-a-Target-Network.md"}'),e={name:"vi/categories/ethical-hacking-labs/2-scanning-networks/0-Scanning-a-Target-Network.md"};function h(r,n,g,o,s,l){return i(),t("div",null,n[0]||(n[0]=[a('<h1 id="quet-mang-muc-tieu" tabindex="-1">Quét Mạng Mục Tiêu <a class="header-anchor" href="#quet-mang-muc-tieu" aria-label="Permalink to &quot;Quét Mạng Mục Tiêu&quot;">​</a></h1><p>Quét mạng (Network Scanning) đề cập đến một tập hợp các quy trình được thực hiện để xác định các máy chủ, cổng và dịch vụ đang chạy trong một mạng.</p><p>Mục đích của việc quét mạng như sau:</p><ul><li>Nhận diện các dịch vụ mạng UDP và TCP khả dụng đang chạy trên các máy chủ mục tiêu.</li><li>Nhận diện các hệ thống lọc giữa người dùng và các máy chủ mục tiêu.</li><li>Xác định hệ điều hành (OS) đang sử dụng bằng cách đánh giá các phản hồi IP.</li><li>Đánh giá tính dự đoán được của số thứ tự chuỗi TCP của máy chủ mục tiêu để xác định tấn công dự đoán chuỗi và giả mạo TCP.</li></ul><p>Nguồn: <a href="https://www.techopedia.com/definition/16124/network-scanning" target="_blank" rel="noreferrer">https://www.techopedia.com/definition/16124/network-scanning</a></p>',5)]))}const d=c(e,[["render",h]]);export{m as __pageData,d as default};
